INSERT INTO TCF_JWT_TOKEN (
    TOKEN_ID, JTI, ISSUER, USER_ID, BRANCH_ID, CHANNEL_ID, AUTH_GROUP_ID,
    TOKEN_TYPE, AUDIENCE, ISSUED_AT, EXPIRES_AT, REVOKED_YN, CLIENT_IP, USER_AGENT
) VALUES (
    #{tokenId}, #{jti}, #{issuer}, #{userId}, #{branchId}, #{channelId}, #{authGroupId},
    #{tokenType}, #{audience}, #{issuedAt}, #{expiresAt}, 'N', #{clientIp}, #{userAgent}
)

mapper.update:
UPDATE TCF_JWT_TOKEN
   SET REVOKED_YN = 'Y',
       REVOKED_AT = #{revokedAt},
       REVOKE_REASON = #{revokeReason}
 WHERE ISSUER = #{issuer}
   AND JTI = #{jti}
   AND REVOKED_YN = 'N'

mapper.insert:
INSERT INTO TCF_REFRESH_TOKEN (
    REFRESH_TOKEN_ID, USER_ID, TOKEN_HASH, TOKEN_FAMILY_ID,
    ISSUED_AT, EXPIRES_AT, ROTATED_YN, REVOKED_YN, CLIENT_IP, USER_AGENT
) VALUES (
    #{refreshTokenId}, #{userId}, #{tokenHash}, #{tokenFamilyId},
    #{issuedAt}, #{expiresAt}, 'N', 'N', #{clientIp}, #{userAgent}
)

mapper.update:
UPDATE TCF_REFRESH_TOKEN
   SET REVOKED_YN = 'Y',
       REVOKED_AT = #{revokedAt}
 WHERE REFRESH_TOKEN_ID = #{refreshTokenId}

